function safe_call(tool, args, state):
    try:
        return ok(tool.run(args))
    except RateLimited(retry_after) as e:
        sleep(retry_after); return retry(safe_call, tool, args, state)
    except ValidationError as e:
        # Surface to the agent so it can fix arguments.
        return tool_error("validation", e.message, hint="fix arguments")
    except ToolUnavailable as e:
        return fallback(tool.fallback or tool_error("no_fallback"))
    except AuthError as e:
        return halt("escalate", e)             # operator must intervene
    except Error as e:
        return tool_error("unknown", str(e))   # let the agent replan

function agent_step(state):
    reply = llm.generate(messages=state.history, tools=TOOLS)
    for call in reply.tool_calls:
        result = safe_call(TOOLS[call.name], call.args, state)
        state.history.append(tool_result(call.id, result))
    return reply

