import asyncio
from claude_agent_sdk import ClaudeAgentOptions, ResultMessage, query
from claude_agent_sdk.types import (
    PermissionResultAllow,
    PermissionResultDeny,
    ToolPermissionContext,
)

IRREVERSIBLE = {"Bash", "Write", "Edit"}


async def can_use_tool(
    tool_name: str, input_data: dict, ctx: ToolPermissionContext
) -> PermissionResultAllow | PermissionResultDeny:
    if tool_name not in IRREVERSIBLE:
        return PermissionResultAllow(updated_input=input_data)

    # 1. Simulate the proposed action against a digital twin / sandbox.
    sim = await simulate_action(tool_name, input_data)
    if sim is None:
        return PermissionResultDeny(
            message="no simulator for this surface; escalate to HITL"
        )

    # 2. Evaluate the predicted delta against invariants.
    verdict = verifier_check(tool_name, input_data, sim.delta)

    if verdict == "pass":
        return PermissionResultAllow(updated_input=input_data)
    if verdict == "fail":
        return PermissionResultDeny(
            message=f"verifier rejected: {sim.delta_summary}"
        )

    # 3. Ambiguous: surface to a reviewer and respect their call.
    decision = await human_review(tool_name, input_data, sim.delta)
    if decision.approved:
        return PermissionResultAllow(updated_input=input_data)
    return PermissionResultDeny(message=decision.reason or "reviewer rejected")


async def main():
    opts = ClaudeAgentOptions(can_use_tool=can_use_tool)
    async for msg in query(prompt="Clean up unused resources", options=opts):
        if isinstance(msg, ResultMessage) and msg.subtype == "success":
            print(msg.result)


asyncio.run(main())

