function run_agent(task, MAX_STEPS):
    messages = [system_prompt, user(task)]
    for step in 1..MAX_STEPS:
        reply = llm.generate(messages=messages, tools=TOOLS)
        messages.append(reply)

        if not reply.tool_calls:
            return ok(reply.content, steps=step)

        for call in reply.tool_calls:
            messages.append(tool_result(call.id, dispatch(call)))

    # Cap hit: the agent did NOT declare done. Return best partial state
    # with a marker so callers can distinguish a real answer from a halt.
    return halt(
        reason="step_budget_exhausted",
        partial=last_assistant_message(messages),
        steps=MAX_STEPS,
    )

function stop_hook(state):
    if state.target_reached:
        return "stop-success"
    if state.step >= MAX_STEPS:
        return "stop-failure:budget"
    if state.last_error and not state.last_error.recoverable:
        return "stop-failure:error"
    # Stagnation: no progress across the last N steps.
    if no_progress(state, window=4):
        return "stop-failure:stagnation"
    return "continue"

function run(state):
    while true:
        state = step(state)
        verdict = stop_hook(state)
        if verdict.startswith("stop"):
            return finalize(state, verdict)

type ToolResult = {
    tool: str,
    trust: "low" | "medium" | "high",     # set by the tool registry
    content_type: str,                     # "text/html", "json", "text/plain"
